CREATE OR REPLACE TEMPORARY TABLE mp_probe AS SELECT CASE WHEN (demo_finance.dbo.settlements.settled_on IS NOT NULL AND demo_finance.dbo.settlements.loaded_at IS NOT NULL AND date_diff('day', demo_finance.dbo.settlements.settled_on, demo_finance.dbo.settlements.loaded_at) >= $1) THEN CAST(date_trunc('month', demo_finance.dbo.settlements.settled_on) AS DATE) ELSE NULL END AS event_month, CASE WHEN (demo_finance.dbo.settlements.settled_on IS NOT NULL AND demo_finance.dbo.settlements.loaded_at IS NOT NULL AND date_diff('day', demo_finance.dbo.settlements.settled_on, demo_finance.dbo.settlements.loaded_at) >= $1 AND date_diff('day', demo_finance.dbo.settlements.settled_on, demo_finance.dbo.settlements.loaded_at) > $2) THEN $3 WHEN (demo_finance.dbo.settlements.settled_on IS NOT NULL AND demo_finance.dbo.settlements.loaded_at IS NOT NULL AND date_diff('day', demo_finance.dbo.settlements.settled_on, demo_finance.dbo.settlements.loaded_at) >= $1 AND date_diff('day', demo_finance.dbo.settlements.settled_on, demo_finance.dbo.settlements.loaded_at) < $4) THEN $5 WHEN (demo_finance.dbo.settlements.settled_on IS NOT NULL AND demo_finance.dbo.settlements.loaded_at IS NOT NULL AND date_diff('day', demo_finance.dbo.settlements.settled_on, demo_finance.dbo.settlements.loaded_at) >= $1) THEN date_diff('day', demo_finance.dbo.settlements.settled_on, demo_finance.dbo.settlements.loaded_at) ELSE NULL END AS lag_day, CAST(demo_finance.dbo.settlements.loaded_at AS DATE) AS load_epoch_day, CASE WHEN (demo_finance.dbo.settlements.settled_on IS NOT NULL AND demo_finance.dbo.settlements.loaded_at IS NOT NULL AND date_diff('day', demo_finance.dbo.settlements.settled_on, demo_finance.dbo.settlements.loaded_at) >= $1) THEN demo_finance.dbo.settlements.batch_run ELSE NULL END AS batch_id, demo_finance.dbo.settlements.region AS alt_value, CASE WHEN (demo_finance.dbo.settlements.settled_on IS NOT NULL AND demo_finance.dbo.settlements.loaded_at IS NOT NULL AND date_diff('day', demo_finance.dbo.settlements.settled_on, demo_finance.dbo.settlements.loaded_at) >= $1) THEN $6 ELSE $7 END AS is_eligible, CASE WHEN (demo_finance.dbo.settlements.settled_on IS NULL) THEN $8 ELSE $9 END AS is_null_event_time, CASE WHEN (demo_finance.dbo.settlements.settled_on IS NOT NULL AND demo_finance.dbo.settlements.loaded_at IS NULL) THEN $10 ELSE $11 END AS is_null_load_time_only, CASE WHEN (demo_finance.dbo.settlements.settled_on IS NOT NULL AND demo_finance.dbo.settlements.loaded_at IS NOT NULL AND date_diff('day', demo_finance.dbo.settlements.settled_on, demo_finance.dbo.settlements.loaded_at) >= $12 AND date_diff('day', demo_finance.dbo.settlements.settled_on, demo_finance.dbo.settlements.loaded_at) < $13) THEN $14 ELSE $15 END AS is_negative_clipped, CASE WHEN (demo_finance.dbo.settlements.settled_on IS NOT NULL AND demo_finance.dbo.settlements.loaded_at IS NOT NULL AND date_diff('day', demo_finance.dbo.settlements.settled_on, demo_finance.dbo.settlements.loaded_at) < $16) THEN $17 ELSE $18 END AS is_negative_lag_excluded, CASE WHEN (demo_finance.dbo.settlements.settled_on IS NOT NULL AND demo_finance.dbo.settlements.loaded_at IS NOT NULL AND date_diff('day', demo_finance.dbo.settlements.settled_on, demo_finance.dbo.settlements.loaded_at) >= $1 AND date_diff('day', demo_finance.dbo.settlements.settled_on, demo_finance.dbo.settlements.loaded_at) > $19) THEN $20 ELSE $21 END AS is_overflow, CAST($22 AS INTEGER) AS is_join_unmatched, CAST($23 AS INTEGER) AS is_base_row, CAST($24 AS INTEGER) AS is_ambiguous_base, CASE WHEN (demo_finance.dbo.settlements.settled_on IS NOT NULL AND demo_finance.dbo.settlements.loaded_at IS NOT NULL AND date_diff('day', demo_finance.dbo.settlements.settled_on, demo_finance.dbo.settlements.loaded_at) >= $1 AND (demo_finance.dbo.settlements.settled_on_raw IS NULL OR date_diff('day', demo_finance.dbo.settlements.settled_on, demo_finance.dbo.settlements.settled_on_raw) != $25)) THEN $26 ELSE $27 END AS is_compare_mismatch, CAST(NULL AS INTEGER) AS lookup_dup, sha256(CASE WHEN demo_finance.dbo.settlements.settlement_id IS NULL THEN chr(0) ELSE '1' || lpad(CAST(length('bigint') AS VARCHAR), 10, '0') || 'bigint' || lpad(CAST(length(CAST(demo_finance.dbo.settlements.settlement_id AS VARCHAR)) AS VARCHAR), 10, '0') || CAST(demo_finance.dbo.settlements.settlement_id AS VARCHAR) END || CASE WHEN demo_finance.dbo.settlements.leg IS NULL THEN chr(0) ELSE '1' || lpad(CAST(length('varchar') AS VARCHAR), 10, '0') || 'varchar' || lpad(CAST(length(CAST(demo_finance.dbo.settlements.leg AS VARCHAR)) AS VARCHAR), 10, '0') || CAST(demo_finance.dbo.settlements.leg AS VARCHAR) END) AS key_hash, demo_finance.dbo.settlements.loaded_at AS load_time 
FROM demo_finance.dbo.settlements 
WHERE demo_finance.dbo.settlements.loaded_at <= $28 OR demo_finance.dbo.settlements.loaded_at IS NULL
